43	const sum = (numbers: number[]): number =>
44	  numbers.reduce((total, n) => total + n, 0);
45	
46	const policyInsuranceSum = (items: Item[]): number =>
47	  sum(items.map((item) => INSURANCE_VALUES[item.type]));
48	
49	const isHighEnchantmentForReimbursement = (item: Item): boolean =>
50	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD;
51	
52	const effectiveDamage = (item: Item, damageAmount: number): number =>
53	  isHighEnchantmentForReimbursement(item)
54	    ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
55	    : damageAmount;
56	
57	const claimResult = (policyItems: Item[], step: ClaimStep) => {
58	  const cap = CAP_MULTIPLIER * policyInsuranceSum(policyItems);
59	  const payout = sum(
60	    step.incident.damages.map((damage) => {
61	      const damagedItem = policyItems.find((item) => item.type === damage.itemType)!;
62	      return effectiveDamage(damagedItem, damage.amount) - DEDUCTIBLE;
63	    }),
64	  );
65	  return { payout, remainingCap: cap - payout };
66	};
67	
68	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
69	
70	const isBlockOfThreeAlike = (items: Item[]): boolean =>
71	  items.length === 3 && items.every((item) => item.type === items[0].type);
72	
73	const groupByType = (items: Item[]): Item[][] => {
74	  const groups: Record<string, Item[]> = {};
75	  for (const item of items) {
76	    (groups[item.type] ||= []).push(item);
77	  }
78	  return Object.values(groups);
79	};
80	
81	const groupBasePremium = (group: Item[]): number =>
82	  isBlockOfThreeAlike(group)
83	    ? BLOCK_OF_THREE_BASE_PREMIUM
84	    : sum(group.map(itemBasePremium));
85	
86	const itemsBasePremium = (items: Item[]): number =>
87	  sum(groupByType(items).map(groupBasePremium));
88	
89	const rateIfApplies = (amount: number, applies: boolean, rate: number): number =>
90	  applies ? amount * rate : 0;
91	
92	const cursedSurcharge = (item: Item): number =>
93	  rateIfApplies(itemBasePremium(item), item.cursed === true, CURSED_SURCHARGE_RATE);
94	
95	const highEnchantmentSurcharge = (item: Item): number =>
96	  rateIfApplies(
97	    itemBasePremium(item),
98	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
99	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
100	  );
101	
102	const itemSurchargesTotal = (items: Item[]): number =>
103	  sum(items.map((item) => cursedSurcharge(item) + highEnchantmentSurcharge(item)));
104	
105	const firstInsuranceSurcharge = (basePremium: number): number =>
106	  basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
107	
108	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
109	  rateIfApplies(
110	    basePremium,
111	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS,
112	    LOYALTY_DISCOUNT_RATE,
113	  );
114	
115	const followupDiscount = (basePremium: number, quoteIndex: number): number =>
116	  rateIfApplies(basePremium, quoteIndex >= 1, FOLLOWUP_DISCOUNT_RATE);
117	
118	const quotePremiumFor = (items: Item[], customer: Customer, quoteIndex: number): number => {
119	  const policyBase = itemsBasePremium(items);
120	  return Math.ceil(
121	    policyBase +
122	      itemSurchargesTotal(items) +
123	      firstInsuranceSurcharge(policyBase) -
124	      loyaltyDiscount(policyBase, customer) -
125	      followupDiscount(policyBase, quoteIndex) +
126	      PROCESSING_FEE,
127	  );
128	};
129	
130	export const runScenario = (input: Scenario): unknown => {
131	  const results: unknown[] = [];
132	  const quotedPolicies: Item[][] = [];
133	  for (const step of input.steps) {
134	    if (step.op === "quote") {
135	      const premium = quotePremiumFor(step.items, input.customer, quotedPolicies.length);
136	      results.push({ premium });
137	      quotedPolicies.push(step.items);
138	    } else {
139	      results.push(claimResult(quotedPolicies[step.policy], step));
140	    }
141	  }
142	  return { results };
143	};
